func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestCostIncrease := 1e18 // large number representing infinity
		bestIdx := -1

		oldCosts := make([]float64, dispatch.AssignsLen+1)

		// evaluate all existing non‑empty assignments
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].StationsLen == 0 {
				continue
			}
			oldCost := dispatch.Assigns[i].Cost
			oldCosts[i] = oldCost

			if dispatch.Assigns[i].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					inc := newCost - oldCost
					if inc < bestCostIncrease {
						bestCostIncrease = inc
						bestIdx = i
					}
				}
				// revert
				dispatch.Assigns[i].RemoveShip(total_ship + jj)
				dispatch.Assigns[i].GenRoute()
			}
		}

		// evaluate inserting into a brand‑new assignment if space allows
		canNew := dispatch.AssignsLen < MAXASSIGNS
		if canNew {
			i := dispatch.AssignsLen
			oldCosts[i] = 0.0 // empty assignment has zero cost
			if dispatch.Assigns[i].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					inc := newCost
					if inc < bestCostIncrease {
						bestCostIncrease = inc
						bestIdx = i
					}
				}
				// revert
				dispatch.Assigns[i].RemoveShip(total_ship + jj)
				dispatch.Assigns[i].GenRoute()
			}
		}

		if bestIdx != -1 {
			// apply the best insertion found
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
			if bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestIdx + 1
			}
		} else {
			// fallback: force a new assignment; if full, force into the last assignment
			if dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[idx].GenRoute()
				dispatch.AssignsLen++
			} else {
				last := dispatch.AssignsLen - 1
				dispatch.Assigns[last].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[last].GenRoute()
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

